mapper.select:
SELECT DISTINCT dgm.group_id FROM defense_group_member dgm
INNER JOIN defense_group dg ON dgm.group_id = dg.group_id AND dg.is_deleted = 0
WHERE dgm.is_deleted = 0
AND dgm.user_id = #{teacherId}
AND dgm.user_type = 'TEACHER'

    AND dg.academic_year = #{academicYear}

SELECT user_id FROM defense_group_member
WHERE is_deleted = 0 AND group_id = #{groupId} AND user_type = 'STUDENT'

    AND user_id = #{studentId}
